class Solution:
    def pathSum(self, root, targetSum):
        res = []
        def walk(node, path):
            if node is None:
                return
            path = path + [node.val]
            if node.left is None and node.right is None:
                if sum(path) == targetSum:
                    res.append(path)
                return
            walk(node.left, path)
            walk(node.right, path)
        walk(root, [])
        return res

