class Solution:
    def pathSum(self, root, targetSum):
        res = []
        path = []
        def dfs(node, remaining):
            if node is None:
                return
            path.append(node.val)
            remaining -= node.val
            if node.left is None and node.right is None and remaining == 0:
                res.append(path[:])
            else:
                dfs(node.left, remaining)
                dfs(node.right, remaining)
            path.pop()
        dfs(root, targetSum)
        return res

