var pathSum = function(root, targetSum) {
    const res = [];
    const path = [];
    function dfs(node, remaining) {
        if (!node) return;
        path.push(node.val);
        remaining -= node.val;
        if (!node.left && !node.right && remaining === 0) {
            res.push(path.slice());
        } else {
            dfs(node.left, remaining);
            dfs(node.right, remaining);
        }
        path.pop();
    }
    dfs(root, targetSum);
    return res;
};
